package users

// UserError exposes reusable message-based sentinel errors for the users domain.
type UserError interface {
	error
	Message() string
}

type staticUserError struct {
	message string
}

func (e staticUserError) Error() string   { return e.message }
func (e staticUserError) Message() string { return e.message }

type userErrorFactory interface {
	New(message string) UserError
}

type staticUserErrorFactory struct{}

func (staticUserErrorFactory) New(message string) UserError {
	return staticUserError{message: message}
}

func newDomainError(message string) error {
	return staticUserErrorFactory{}.New(message)
}

var (
	// ErrUserNotFound indicates that the requested user does not exist.
	ErrUserNotFound = newDomainError("user not found")
	// ErrUserAlreadyExists indicates that a create request conflicts with an existing user.
	ErrUserAlreadyExists = newDomainError("user already exists")
	// ErrInvalidCredentials indicates that password verification failed.
	ErrInvalidCredentials = newDomainError("invalid credentials")
	// ErrInsufficientBalance indicates that the user would exceed allowed debt.
	ErrInsufficientBalance = newDomainError("insufficient balance")
	// ErrInvalidUserData indicates that caller-supplied user data is invalid.
	ErrInvalidUserData = newDomainError("invalid user data")
	// ErrUnauthorized indicates that the caller is not allowed to perform the action.
	ErrUnauthorized = newDomainError("unauthorized")
	// ErrInvalidTransactionType indicates that no balance rule exists for the supplied transaction type.
	ErrInvalidTransactionType = newDomainError("invalid transaction type")
)

package users

import (
	"time"
)

const personalLinkFieldCount = 4

// User represents the core user domain model
type User struct {
	ID                    int64
	Username              string
	DisplayName           string
	Email                 string
	UserType              string
	InitialAccountBalance int64
	AccountBalance        int64
	PersonalEmoji         string
	Description           string
	PersonalLink1         string
	PersonalLink2         string
	PersonalLink3         string
	PersonalLink4         string
	APIKey                string
	MustChangePassword    bool
	CreatedAt             time.Time
	UpdatedAt             time.Time
}

// ToPublicUser returns the public-safe projection of the user model.
func (u *User) ToPublicUser() *PublicUser {
	if u == nil {
		return nil
	}

	publicUser := &PublicUser{
		ID:                    u.ID,
		Username:              u.Username,
		DisplayName:           u.DisplayName,
		UserType:              u.UserType,
		InitialAccountBalance: u.InitialAccountBalance,
		AccountBalance:        u.AccountBalance,
		PersonalEmoji:         u.PersonalEmoji,
		Description:           u.Description,
	}
	u.PersonalLinks().ApplyToPublicUser(publicUser)
	return publicUser
}

// ToPrivateProfile returns the authenticated private projection of the user model.
func (u *User) ToPrivateProfile() *PrivateProfile {
	if u == nil {
		return nil
	}

	privateProfile := &PrivateProfile{
		ID:                    u.ID,
		Username:              u.Username,
		DisplayName:           u.DisplayName,
		UserType:              u.UserType,
		InitialAccountBalance: u.InitialAccountBalance,
		AccountBalance:        u.AccountBalance,
		PersonalEmoji:         u.PersonalEmoji,
		Description:           u.Description,
		Email:                 u.Email,
		APIKey:                u.APIKey,
		MustChangePassword:    u.MustChangePassword,
		CreatedAt:             u.CreatedAt,
		UpdatedAt:             u.UpdatedAt,
	}
	u.PersonalLinks().ApplyToPrivateProfile(privateProfile)
	return privateProfile
}

// ApplyUpdate mutates the user with the fields supported by UserUpdateRequest.
func (u *User) ApplyUpdate(req UserUpdateRequest) {
	if u == nil {
		return
	}

	u.DisplayName = req.DisplayName
	u.Description = req.Description
	u.PersonalEmoji = req.PersonalEmoji
	req.PersonalLinks().ApplyTo(u)
}

// PersonalLinks returns the personal-link fields currently stored on the user.
func (u *User) PersonalLinks() PersonalLinks {
	if u == nil {
		return PersonalLinks{}
	}

	return PersonalLinks{
		PersonalLink1: u.PersonalLink1,
		PersonalLink2: u.PersonalLink2,
		PersonalLink3: u.PersonalLink3,
		PersonalLink4: u.PersonalLink4,
	}
}

// PublicUser represents the public view of a user
type PublicUser struct {
	ID                    int64
	Username              string
	DisplayName           string
	UserType              string
	InitialAccountBalance int64
	AccountBalance        int64
	PersonalEmoji         string
	Description           string
	PersonalLink1         string
	PersonalLink2         string
	PersonalLink3         string
	PersonalLink4         string
}

// UserCreateRequest represents the data needed to create a new user
type UserCreateRequest struct {
	Username    string
	DisplayName string
	Email       string
	Password    string
	UserType    string
}

// NewUser builds the default domain user entity for the request.
func (r UserCreateRequest) NewUser() *User {
	return &User{
		Username:              r.Username,
		DisplayName:           r.DisplayName,
		Email:                 r.Email,
		UserType:              r.UserType,
		InitialAccountBalance: 0,
		AccountBalance:        0,
		MustChangePassword:    true,
	}
}

// UserUpdateRequest represents the data that can be updated for a user
type UserUpdateRequest struct {
	DisplayName   string
	Description   string
	PersonalEmoji string
	PersonalLink1 string
	PersonalLink2 string
	PersonalLink3 string
	PersonalLink4 string
}

// PersonalLinks returns the request's personal-link values in the domain storage shape.
func (r UserUpdateRequest) PersonalLinks() PersonalLinks {
	return PersonalLinks{
		PersonalLink1: r.PersonalLink1,
		PersonalLink2: r.PersonalLink2,
		PersonalLink3: r.PersonalLink3,
		PersonalLink4: r.PersonalLink4,
	}
}

// UserBet represents a bet placed by a user.
type UserBet struct {
	MarketID uint
	PlacedAt time.Time
}

// MarketUserPosition represents a user's position within a market.
type MarketUserPosition struct {
	YesSharesOwned int64
	NoSharesOwned  int64
}

// PortfolioItem captures aggregate information for a market within a user's portfolio.
type PortfolioItem struct {
	MarketID       uint
	QuestionTitle  string
	YesSharesOwned int64
	NoSharesOwned  int64
	LastBetPlaced  time.Time
}

// Portfolio represents the user's overall market positions.
type Portfolio struct {
	Items            []PortfolioItem
	TotalSharesOwned int64
}

// UserMarket represents a market a user has participated in.
type UserMarket struct {
	ID                      int64
	QuestionTitle           string
	Description             string
	OutcomeType             string
	ResolutionDateTime      time.Time
	FinalResolutionDateTime time.Time
	UTCOffset               int
	IsResolved              bool
	ResolutionResult        string
	InitialProbability      float64
	YesLabel                string
	NoLabel                 string
	CreatorUsername         string
	CreatedAt               time.Time
	UpdatedAt               time.Time
}

// PersonalLinks captures the set of personal links associated with a user profile.
type PersonalLinks struct {
	PersonalLink1 string
	PersonalLink2 string
	PersonalLink3 string
	PersonalLink4 string
}

// Values returns the links in storage order for bulk validation or sanitization.
func (p PersonalLinks) Values() []string {
	return []string{
		p.PersonalLink1,
		p.PersonalLink2,
		p.PersonalLink3,
		p.PersonalLink4,
	}
}

// NewPersonalLinks rebuilds personal links from an ordered value slice.
func NewPersonalLinks(values []string) PersonalLinks {
	if len(values) > personalLinkFieldCount {
		values = values[:personalLinkFieldCount]
	}

	links := PersonalLinks{}
	if len(values) > 0 {
		links.PersonalLink1 = values[0]
	}
	if len(values) > 1 {
		links.PersonalLink2 = values[1]
	}
	if len(values) > 2 {
		links.PersonalLink3 = values[2]
	}
	if len(values) > 3 {
		links.PersonalLink4 = values[3]
	}
	return links
}

// ApplyTo updates the mutable personal-link fields on the user.
func (p PersonalLinks) ApplyTo(user *User) {
	if user == nil {
		return
	}

	user.PersonalLink1 = p.PersonalLink1
	user.PersonalLink2 = p.PersonalLink2
	user.PersonalLink3 = p.PersonalLink3
	user.PersonalLink4 = p.PersonalLink4
}

// ApplyToPublicUser updates the public personal-link fields.
func (p PersonalLinks) ApplyToPublicUser(user *PublicUser) {
	if user == nil {
		return
	}

	user.PersonalLink1 = p.PersonalLink1
	user.PersonalLink2 = p.PersonalLink2
	user.PersonalLink3 = p.PersonalLink3
	user.PersonalLink4 = p.PersonalLink4
}

// ApplyToPrivateProfile updates the private-profile personal-link fields.
func (p PersonalLinks) ApplyToPrivateProfile(profile *PrivateProfile) {
	if profile == nil {
		return
	}

	profile.PersonalLink1 = p.PersonalLink1
	profile.PersonalLink2 = p.PersonalLink2
	profile.PersonalLink3 = p.PersonalLink3
	profile.PersonalLink4 = p.PersonalLink4
}

// Credentials represents the sensitive authentication fields associated with a user.
type Credentials struct {
	PasswordHash       string
	MustChangePassword bool
}

// PrivateProfile combines public and private user information for authenticated views.
type PrivateProfile struct {
	ID                    int64
	Username              string
	DisplayName           string
	UserType              string
	InitialAccountBalance int64
	AccountBalance        int64
	PersonalEmoji         string
	Description           string
	PersonalLink1         string
	PersonalLink2         string
	PersonalLink3         string
	PersonalLink4         string
	Email                 string
	APIKey                string
	MustChangePassword    bool
	CreatedAt             time.Time
	UpdatedAt             time.Time
}

package users

type balanceAdjustment func(balance int64, amount int64) int64

// Transaction types supported when adjusting user balances.
const (
	TransactionWin    = "WIN"
	TransactionRefund = "REFUND"
	TransactionSale   = "SALE"
	TransactionBuy    = "BUY"
	TransactionFee    = "FEE"
)

var transactionBalanceAdjustments = map[string]balanceAdjustment{
	TransactionWin:    creditBalance,
	TransactionRefund: creditBalance,
	TransactionSale:   creditBalance,
	TransactionBuy:    debitBalance,
	TransactionFee:    debitBalance,
}

func creditBalance(balance int64, amount int64) int64 {
	return balance + amount
}

func debitBalance(balance int64, amount int64) int64 {
	return balance - amount
}

func applyTransactionBalance(balance int64, amount int64, transactionType string) (int64, error) {
	adjust, ok := transactionBalanceAdjustments[transactionType]
	if !ok {
		return 0, ErrInvalidTransactionType
	}
	return adjust(balance, amount), nil
}

package users_test

import (
	"context"
	"testing"

	analytics "socialpredict/internal/domain/analytics"
	users "socialpredict/internal/domain/users"
	rusers "socialpredict/internal/repository/users"
	"socialpredict/models/modelstesting"
	"socialpredict/security"
)

type fakeAnalyticsService struct {
	computeUserFinancialsFn func(context.Context, analytics.FinancialSnapshotRequest) (*analytics.FinancialSnapshot, error)
}

func (f fakeAnalyticsService) ComputeUserFinancials(ctx context.Context, req analytics.FinancialSnapshotRequest) (*analytics.FinancialSnapshot, error) {
	if f.computeUserFinancialsFn != nil {
		return f.computeUserFinancialsFn(ctx, req)
	}
	return &analytics.FinancialSnapshot{}, nil
}

func TestServiceApplyTransaction(t *testing.T) {
	db := modelstesting.NewFakeDB(t)
	repo := rusers.NewGormRepository(db)
	service := users.NewService(repo, fakeAnalyticsService{}, security.NewSecurityService().Sanitizer)

	user := modelstesting.GenerateUser("tx_user", 0)
	user.AccountBalance = 100
	if err := db.Create(&user).Error; err != nil {
		t.Fatalf("create user: %v", err)
	}

	tests := []struct {
		name        string
		txType      string
		amount      int64
		wantBalance int64
		wantErr     bool
	}{
		{"win adds funds", users.TransactionWin, 50, 150, false},
		{"refund adds funds", users.TransactionRefund, 30, 180, false},
		{"sale adds funds", users.TransactionSale, 20, 200, false},
		{"buy subtracts funds", users.TransactionBuy, 40, 160, false},
		{"fee subtracts funds", users.TransactionFee, 10, 150, false},
		{"invalid type", "UNKNOWN", 5, 150, true},
	}

	ctx := context.Background()

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			err := service.ApplyTransaction(ctx, user.Username, tt.amount, tt.txType)
			if tt.wantErr {
				if err == nil {
					t.Fatalf("expected error, got nil")
				}
				return
			}
			if err != nil {
				t.Fatalf("ApplyTransaction returned error: %v", err)
			}

			var updatedBalance int64
			if err := db.Model(&user).Select("account_balance").Where("username = ?", user.Username).Scan(&updatedBalance).Error; err != nil {
				t.Fatalf("scan balance: %v", err)
			}
			if updatedBalance != tt.wantBalance {
				t.Fatalf("balance = %d, want %d", updatedBalance, tt.wantBalance)
			}
		})
	}
}

func TestServiceGetUserCredit(t *testing.T) {
